const b = $input.first().json.body || $input.first().json;

const city              = b.city             || '';
const area              = b.area             || '';
const locality          = b.locality         || '';
const country           = b.country          || 'Australia';
const business_type     = b.business_type    || '';
const industry_category = b.industry_category || '';
const target_segments   = b.target_customer_segments || [];
const email             = b.email            || '';

// FIX 1: Geocode the SUBURB directly, not "locality, area, city"
// "Brunswick Street, Fitzroy, Melbourne" resolves to CBD
// "Fitzroy VIC 3065" resolves correctly to the suburb centroid
const SUBURB_POSTCODES = {
  'fitzroy':'3065','fitzroy north':'3068','collingwood':'3066','abbotsford':'3067',
  'carlton':'3053','carlton north':'3054','richmond':'3121','northcote':'3070',
  'brunswick':'3056','brunswick east':'3057','clifton hill':'3068','north melbourne':'3051',
  'south yarra':'3141','prahran':'3181','st kilda':'3182','elwood':'3184',
  'hawthorn':'3122','camberwell':'3124','surry hills':'2010','newtown':'2042',
  'fortitude valley':'4006','new farm':'4005','west end':'4101','subiaco':'6008',
  'norwood':'5067','braddon':'2612'
};
const areaKey = area.toLowerCase().trim();
const knownPostcode = SUBURB_POSTCODES[areaKey] || '';

// Use "Suburb VIC postcode" format for Nominatim — much more accurate
const stateGuess = ({'Melbourne':'VIC','Sydney':'NSW','Brisbane':'QLD','Perth':'WA','Adelaide':'SA','Canberra':'ACT','Hobart':'TAS','Darwin':'NT'})[city] || 'VIC';
const geo_query = knownPostcode
  ? `${area} ${stateGuess} ${knownPostcode}`
  : `${area} ${stateGuess} Australia`;

const abs_postcode = knownPostcode || '';

return [{ json: {
  city, area, locality, country,
  business_type, industry_category,
  target_customer_segments: target_segments,
  email, geo_query,
  abs_postcode,
  state_guess: stateGuess,
  radius_m: 500
}}];

const geo  = $input.first().json;
const prev = $('Parse & Validate Inputs').first().json;

const result = Array.isArray(geo) ? geo[0] : null;
let lat = null, lon = null, postcode = null, suburb = null, state = null;

if (result) {
  lat      = parseFloat(result.lat);
  lon      = parseFloat(result.lon);
  postcode = result.address?.postcode || null;
  suburb   = result.address?.suburb || result.address?.locality || result.address?.town || prev.area;
  state    = result.address?.state || result.address?.state_code || '';
}

// Known suburb centroids — use these if Nominatim returns wrong coords
// Detected wrong: if lat/lon is within 500m of Melbourne CBD (-37.8136, 144.9631)
const SUBURB_CENTROIDS = {
  'fitzroy':         {lat:-37.7985,lon:144.9784,postcode:'3065'},
  'fitzroy north':   {lat:-37.7817,lon:144.9817,postcode:'3068'},
  'collingwood':     {lat:-37.8030,lon:144.9875,postcode:'3066'},
  'abbotsford':      {lat:-37.8027,lon:144.9981,postcode:'3067'},
  'carlton':         {lat:-37.7990,lon:144.9662,postcode:'3053'},
  'richmond':        {lat:-37.8183,lon:144.9971,postcode:'3121'},
  'northcote':       {lat:-37.7710,lon:144.9990,postcode:'3070'},
  'brunswick':       {lat:-37.7668,lon:144.9619,postcode:'3056'},
  'north melbourne': {lat:-37.7993,lon:144.9451,postcode:'3051'},
  'south yarra':     {lat:-37.8400,lon:144.9920,postcode:'3141'},
  'st kilda':        {lat:-37.8583,lon:144.9819,postcode:'3182'},
  'prahran':         {lat:-37.8499,lon:144.9900,postcode:'3181'},
  'hawthorn':        {lat:-37.8226,lon:145.0351,postcode:'3122'},
  'surry hills':     {lat:-33.8852,lon:151.2102,postcode:'2010'},
  'newtown':         {lat:-33.8967,lon:151.1794,postcode:'2042'},
  'fortitude valley':{lat:-27.4591,lon:153.0354,postcode:'4006'},
  'west end':        {lat:-27.4794,lon:153.0100,postcode:'4101'},
  'subiaco':         {lat:-31.9455,lon:115.8327,postcode:'6008'},
  'norwood':         {lat:-34.9212,lon:138.6363,postcode:'5067'},
};

function distKm(a, b, c, d) {
  const R = 6371, dL=(c-a)*Math.PI/180, dl=(d-b)*Math.PI/180;
  const x = Math.sin(dL/2)**2 + Math.cos(a*Math.PI/180)*Math.cos(c*Math.PI/180)*Math.sin(dl/2)**2;
  return R*2*Math.atan2(Math.sqrt(x),Math.sqrt(1-x));
}

const areaKey = (prev.area || '').toLowerCase().trim();
const centroid = SUBURB_CENTROIDS[areaKey];

// Use hardcoded centroid if: Nominatim failed OR returned CBD (within 2km of -37.8136,144.9631)
const cbdDist = lat && lon ? distKm(lat, lon, -37.8136, 144.9631) : 999;
const useHardcoded = centroid && (!lat || !lon || cbdDist < 2.0);
if (useHardcoded) {
  lat      = centroid.lat;
  lon      = centroid.lon;
  postcode = postcode || centroid.postcode;
}

// Ensure postcode from known map
if (!postcode && centroid) postcode = centroid.postcode;
if (!postcode && prev.abs_postcode) postcode = prev.abs_postcode;

// State fallbacks
const stateFallbacks = {'Melbourne':'VIC','Sydney':'NSW','Brisbane':'QLD','Perth':'WA','Adelaide':'SA','Canberra':'ACT','Hobart':'TAS','Darwin':'NT'};
if (!state || state.length > 4) state = stateFallbacks[prev.city] || 'VIC';

const abs_postcode = postcode ? postcode.replace(/^0+/,'') : null;

return [{ json: {
  ...prev,
  lat, lon, postcode, abs_postcode,
  suburb: suburb || prev.area,
  state,
  geocode_success: !!(lat && lon),
  used_hardcoded_centroid: useHardcoded || false,
  cbd_dist_km: Math.round(cbdDist*100)/100
}}];

// ── Cache check (Supabase) ──
// TODO: Before calling expensive APIs, check:
// SELECT * FROM agent_cache WHERE cache_key = MD5(city+area+business_type+agent_id)
//   AND updated_at > NOW() - INTERVAL '7 days'
// If cache hit → return cached data immediately
// Implementation: add a Supabase HTTP call before API calls with cache_key lookup

const all    = $input.all();
const coords = $('Extract Coordinates & Postcode').first().json;

// ── PARSE INPUTS BY MERGE POSITION ──────────────────────
// Merge order: [0]=G02, [1]=WPI, [2]=SEIFA, [3]=Transit, [4]=Edu, [5]=Demand
let absG02Data = null, wpiData = null, seifaData = null;
let transit_count = 0, edu_count = 0, demand_count = 0;

function getOverpassCount(j) {
  if (!j) return 0;
  // Handle neverError HTML responses (gateway timeout etc)
  if (typeof j === 'string') return 0;
  if (!Array.isArray(j.elements)) return 0;
  if (j.elements.length === 0) return 0;
  // 'out count' format: [{type:'count', id:0, tags:{total:'N'}}]
  const first = j.elements[0];
  if (first?.type === 'count' && first?.tags?.total !== undefined) {
    return parseInt(first.tags.total) || 0;
  }
  // Some mirrors use tags.nodes + tags.ways + tags.relations
  if (first?.tags?.nodes !== undefined) {
    return (parseInt(first.tags.nodes)||0) + (parseInt(first.tags.ways)||0) + (parseInt(first.tags.relations)||0);
  }
  // Fallback: raw element count (for 'out body' responses)
  return j.elements.length;
}

// ── DETECTION: ABS by dataSets, Overpass by _type:'combined' ──
for (const item of all) {
  const j = item?.json;
  if (!j) continue;

  // Single combined Overpass response
  if (j._type === 'combined') {
    transit_count = parseInt(j.transit_count) || 0;
    edu_count     = parseInt(j.edu_count)     || 0;
    demand_count  = parseInt(j.demand_count)  || 0;
    continue;
  }

  // ABS SDMX-JSON responses — v2 API returns data.dataSets
  if (j?.data?.dataSets !== undefined) {
    const seriesCount = Object.keys(j.data?.dataSets?.[0]?.series || {}).length;
    if (seriesCount >= 10 && !absG02Data) absG02Data = j;
    else if (!wpiData)                    wpiData    = j;
    else if (!seifaData)                  seifaData  = j;
  }
}

// ── PARSE ABS G02 ─────────────────────────────────────────
// SDMX-JSON with dimensionAtObservation=AllDimensions puts each obs as a key
// Key format: "REGION:MEASURE:FREQ" e.g. "POA3065:3:A"
// G02 measures: 0=Tot_P_P, 3=Median_tot_prsnl_inc_weekly, 7=Median_age, 15=Median_rent_weekly
let abs_median_weekly_income = null, abs_population = null;
let abs_median_age = null, abs_median_weekly_rent = null;
let abs_data_found = false;

// ── ABS G02 Parser — handles both v1 and v2 SDMX-JSON formats ──
if (absG02Data?.data?.dataSets) {
  const ds = absG02Data.data.dataSets[0];
  const struct = absG02Data.data.structure;

  // Get measure dimension names to map indices to field names
  const measureDimension = struct?.dimensions?.series?.find(d => d.id === 'MEASURE')
    || struct?.dimensions?.observation?.find(d => d.id === 'MEASURE');
  const measureValues = measureDimension?.values || [];

  // Known G02 measure IDs (ABS Census 2021)
  const MEASURE_MAP = {
    'Tot_P_P': 'population',
    'Median_tot_prsnl_inc_weekly': 'income',
    'Median_age_persons': 'age',
    'Median_rent_weekly': 'rent'
  };

  function extractFromSeries(series) {
    for (const [key, val] of Object.entries(series)) {
      const obs = val.observations;
      if (!obs) continue;
      const v = Object.values(obs)?.[0]?.[0];
      if (v === null || v === undefined || isNaN(parseFloat(v))) continue;
      const num = parseFloat(v);
      if (num <= 0) continue;
      abs_data_found = true;

      // Try to match by measure name from structure
      const parts = key.split(':');
      const measureIdx = parseInt(parts[1] ?? parts[0] ?? '99');
      const measureId = measureValues[measureIdx]?.id || '';
      const field = MEASURE_MAP[measureId] || '';

      if (field === 'population' || (measureIdx === 0 && !abs_population))           abs_population           = num;
      if (field === 'income'     || (measureIdx === 3 && !abs_median_weekly_income)) abs_median_weekly_income = num;
      if (field === 'age'        || (measureIdx === 7 && !abs_median_age))           abs_median_age           = num;
      if (field === 'rent'       || (measureIdx === 15 && !abs_median_weekly_rent))  abs_median_weekly_rent   = num;
    }
  }

  function extractFromObservations(obs) {
    // v2 flat observations: key = "dim0:dim1:dim2:...", value = [obs_val, ...]
    for (const [key, valArr] of Object.entries(obs)) {
      const v = parseFloat(valArr?.[0]);
      if (!v || v <= 0 || isNaN(v)) continue;
      abs_data_found = true;
      const parts = key.split(':');
      const measureIdx = parseInt(parts[1] ?? '99');
      const measureId = measureValues[measureIdx]?.id || '';
      const field = MEASURE_MAP[measureId] || '';
      if (field === 'population' || (measureIdx === 0 && !abs_population))           abs_population           = v;
      if (field === 'income'     || (measureIdx === 3 && !abs_median_weekly_income)) abs_median_weekly_income = v;
      if (field === 'age'        || (measureIdx === 7 && !abs_median_age))           abs_median_age           = v;
      if (field === 'rent'       || (measureIdx === 15 && !abs_median_weekly_rent))  abs_median_weekly_rent   = v;
    }
  }

  if (ds.series)       extractFromSeries(ds.series);
  if (ds.observations) extractFromObservations(ds.observations);
}

// ── PARSE WPI ─────────────────────────────────────────────
let wpi_value = null;
if (wpiData?.data?.dataSets?.[0]?.series) {
  for (const val of Object.values(wpiData.data.dataSets[0].series)) {
    const obs = val.observations;
    if (!obs) continue;
    const latest = Object.values(obs).sort().pop()?.[0];
    if (latest) { wpi_value = latest; break; }
  }
}
const WPI_BASE_2021 = 112.5;
const wpi_current = wpi_value || 134.0;
const wage_growth_multiplier = wpi_current / WPI_BASE_2021;

// ── PARSE SEIFA ───────────────────────────────────────────
let seifa_score = null, seifa_decile = null;
if (seifaData?.data?.dataSets?.[0]?.series) {
  const vals = [];
  for (const val of Object.values(seifaData.data.dataSets[0].series)) {
    const obs = val.observations;
    if (!obs) continue;
    const v = Object.values(obs)?.[0]?.[0];
    if (v && !isNaN(v)) vals.push(v);
  }
  if (vals.length >= 1) seifa_score  = vals[0];
  if (vals.length >= 2) seifa_decile = vals[1];
}

// ── KNOWN SEIFA SCORES FOR COMMON SUBURBS ──
// If API fails, use verified 2021 SEIFA IRSAD scores
const KNOWN_SEIFA = {
  '3065':1062,'3066':1042,'3053':1064,'3121':1064,'3070':1034,
  '3056':1003,'3068':1055,'3067':1056,'3141':1114,'3182':1089,
  '2010':1085,'2042':1070,'4006':1032,'4101':1028,'6008':1095,'5067':1052
};
const pc = coords.postcode;
if (!seifa_score && pc && KNOWN_SEIFA[pc]) seifa_score = KNOWN_SEIFA[pc];

// ── INCOME FALLBACKS ──────────────────────────────────────
const STATE_WEEKLY = {
  'VIC':1100,'NSW':1200,'QLD':1000,'WA':1150,'SA':900,'TAS':850,'ACT':1400,'NT':1050
};
const raw_weekly_income = abs_median_weekly_income ||
  STATE_WEEKLY[coords.state_guess || 'VIC'] || 1000;

const adjusted_weekly  = Math.round(raw_weekly_income * wage_growth_multiplier);
const adjusted_monthly = Math.round(adjusted_weekly * 52 / 12);
const adjusted_annual  = adjusted_weekly * 52;

// ── SEIFA PREMIUM ─────────────────────────────────────────
let seifa_premium = 1.0, seifa_label = 'Average';
if (seifa_score) {
  if      (seifa_score >= 1100) { seifa_premium=1.25; seifa_label='High Advantage'; }
  else if (seifa_score >= 1050) { seifa_premium=1.15; seifa_label='Above Average'; }
  else if (seifa_score >= 950)  { seifa_premium=1.00; seifa_label='Average'; }
  else if (seifa_score >= 900)  { seifa_premium=0.90; seifa_label='Below Average'; }
  else                          { seifa_premium=0.80; seifa_label='Disadvantaged'; }
}
const seifa_adjusted_monthly = Math.round(adjusted_monthly * seifa_premium);

// ── SCORES ────────────────────────────────────────────────
const population = abs_population || 8500;
const pop_density = Math.round(population / 5);

// Foot traffic — FIXED weights for tram-heavy Melbourne inner suburbs
const tramCities = ['melbourne'];
const cityLower = (coords.city||'').toLowerCase();
const isTramCity = tramCities.some(c => cityLower.includes(c));

// Melbourne: tram stops are extremely dense so transit_count will be high in inner suburbs
const transitScore = Math.min(isTramCity ? transit_count * 8 : transit_count * 15, 45);
const demandScore  = Math.min(Math.round(demand_count * 0.12), 30);
const eduBonus     = Math.min(edu_count * 5, 15);
const densityBonus = pop_density >= 5000?10:pop_density>=2000?7:pop_density>=1000?5:2;
const seifaBonus   = seifa_score>=1050?8:seifa_score>=950?4:0;
const foot_traffic_score = Math.min(Math.max(Math.round(transitScore+demandScore+eduBonus+densityBonus+seifaBonus),10),100);
const foot_traffic_label = foot_traffic_score>=75?'High':foot_traffic_score>=55?'Moderate':foot_traffic_score>=35?'Low':'Very Low';

const income_score = Math.min(Math.max(Math.round(((adjusted_weekly-500)/2000)*100),0),100);
const income_label = adjusted_weekly>=2000?'High Income Area':adjusted_weekly>=1400?'Upper-Middle Income':adjusted_weekly>=900?'Middle Income':'Lower-Middle Income';

const biz  = (coords.business_type||'').toLowerCase();
const segs = (coords.target_customer_segments||[]).map(s=>s.toLowerCase()).join(' ');
let fit = 50;
if (biz.includes('café')||biz.includes('cafe')||biz.includes('coffee')) {
  fit += adjusted_weekly>=1500?25:adjusted_weekly>=900?15:5;
} else if (biz.includes('restaurant')||biz.includes('food')) {
  fit += adjusted_weekly>=1200?20:adjusted_weekly>=700?10:5;
} else { fit += adjusted_weekly>=1000?15:8; }
if (segs.includes('professional')) fit += 8;
if (segs.includes('student') && edu_count>=2) fit += 8;
if (segs.includes('family') && seifa_score>=1000) fit += 5;
const demographic_fit = Math.min(Math.max(fit,10),100);

const consumer_affordability = Math.min(Math.max(Math.round((adjusted_weekly/2500)*100*0.7+demographic_fit*0.3),0),100);
const density_score = Math.min(Math.max(Math.round((pop_density/10000)*100),0),100);
const demographics_score = Math.round(foot_traffic_score*0.30+income_score*0.30+demographic_fit*0.25+density_score*0.15);

const est_daily = Math.round(population*0.05*(foot_traffic_score/100)*0.015);

const area_type =
  seifa_score>=1100&&transit_count>=3?'Premium Transit-Connected':
  seifa_score>=1100?'Affluent Residential':
  transit_count>=10?'High-Transit Urban Inner':
  transit_count>=3?'Well-Connected Urban':
  edu_count>=2?'Student/Education Hub':
  demand_count>=8?'Dense Commercial':
  demand_count>=4?'Mixed-Use Urban':'Suburban';

const segmentAlignment = (coords.target_customer_segments||[]).map(seg=>{
  const s=seg.toLowerCase();
  let score=60,alignment='Moderate';
  if(s.includes('student')){score=edu_count>=2?80:55;alignment=edu_count>=2?'Strong':'Moderate';}
  if(s.includes('professional')){score=demand_count>=5?80:60;alignment=demand_count>=5?'Strong':'Moderate';}
  if(s.includes('family')){score=seifa_score>=1000?75:55;alignment=seifa_score>=1000?'Strong':'Moderate';}
  if(s.includes('tourist')){score=transit_count>=5?70:45;alignment=transit_count>=5?'Strong':'Low';}
  return {segment:seg,alignment,score};
});

const demandGenerators=[
  transit_count>0?`${transit_count} transit stop(s) within ${coords.radius_m}m (incl. trams/buses)`:null,
  edu_count>0?`${edu_count} education hub(s) within ${coords.radius_m}m`:null,
  demand_count>0?`${demand_count} demand POIs (cafes/shops/offices/hospitals)`:null,
  seifa_score>=1050?`Above-average suburb (SEIFA ${seifa_score} — ${seifa_label})`:null
].filter(Boolean);

// Premium area flag
const is_premium = seifa_score>=1050 || adjusted_weekly>=1500;
const city_tier = ['sydney','melbourne','brisbane','perth','adelaide'].some(c=>(coords.city||'').toLowerCase().includes(c))?'Tier 1':'Tier 2';
const urban_density = pop_density>=8000?'Very High':pop_density>=4000?'High':pop_density>=1500?'Medium':'Low';

return [{ json: {
  abs_data_found, abs_median_weekly_income: raw_weekly_income,
  abs_population, abs_median_age, abs_median_weekly_rent,
  postcode: coords.postcode, suburb: coords.suburb, state: coords.state_guess,
  wpi_current, wage_growth_multiplier: parseFloat(wage_growth_multiplier.toFixed(3)),
  adjusted_weekly_income: adjusted_weekly,
  adjusted_monthly_income: adjusted_monthly,
  adjusted_annual_income:  adjusted_annual,
  seifa_score, seifa_decile, seifa_label, seifa_premium,
  seifa_adjusted_monthly_income: seifa_adjusted_monthly,
  overpass_transit_count: transit_count,
  overpass_edu_count: edu_count,
  overpass_demand_count: demand_count,
  foot_traffic_score, foot_traffic_label,
  income_score, income_label,
  density_score, consumer_affordability_index: consumer_affordability,
  demographic_fit_score: demographic_fit,
  demographics_score, est_daily_customers: est_daily,
  population_per_sqkm: pop_density,
  area_type, demand_generators: demandGenerators,
  segment_alignment: segmentAlignment,
  is_premium_area: is_premium, city_tier, urban_density,
  city: coords.city, area: coords.area, locality: coords.locality,
  business_type: coords.business_type, industry_category: coords.industry_category,
  target_customer_segments: coords.target_customer_segments,
  email: coords.email, lat: coords.lat, lon: coords.lon,
  radius_m: coords.radius_m, geocode_success: coords.geocode_success,
  used_hardcoded_centroid: coords.used_hardcoded_centroid
}}];

const inputJson = $input.first().json;
const rawText = inputJson.output || inputJson.text || JSON.stringify(inputJson);
let analysis;
try {
  let cleaned = rawText.trim()
    .replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();
  const s=cleaned.indexOf('{'),e=cleaned.lastIndexOf('}');
  if(s!==-1&&e>s) cleaned=cleaned.slice(s,e+1);
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { parse_error:true, raw_response: rawText.slice(0,800) };
}

const sc = $('Compute All Scores (ABS + WPI + SEIFA)').first().json;

return [{ json: {
  agent_id:'A6',
  agent_name:'Demographics & Foot Traffic (Australian)',
  status: analysis.parse_error?'error':'success',
  timestamp: new Date().toISOString(),
  email: sc.email,
  inputs_used: {
    city:sc.city,area:sc.area,locality:sc.locality,
    business_type:sc.business_type,postcode:sc.postcode,
    suburb:sc.suburb,state:sc.state,lat:sc.lat,lon:sc.lon,
    radius_m:sc.radius_m,geocode_success:sc.geocode_success,
    used_hardcoded_centroid:sc.used_hardcoded_centroid
  },
  data_sources: {
    geocoding:'OpenStreetMap Nominatim (free)',
    census:    sc.abs_data_found?'ABS 2021 Census C21_G02_POA (real)':'ABS state-level estimate',
    wage_index:'ABS Wage Price Index (live quarterly)',
    seifa:     sc.seifa_score?'ABS SEIFA 2021 (real or known suburb value)':'Not available',
    poi_data:  'OSM Overpass API (POST — tram/bus/train + demand POIs)',
    ai_analysis:'GPT-4o'
  },
  abs_raw: {
    median_weekly_income_2021:sc.abs_median_weekly_income,
    population:sc.abs_population,median_age:sc.abs_median_age,
    median_weekly_rent_2021:sc.abs_median_weekly_rent,data_found:sc.abs_data_found
  },
  wpi: {
    index_value:sc.wpi_current,
    growth_multiplier:sc.wage_growth_multiplier,
    growth_pct:Math.round((sc.wage_growth_multiplier-1)*100)
  },
  seifa: {score:sc.seifa_score,decile:sc.seifa_decile,label:sc.seifa_label,premium:sc.seifa_premium},
  outputs: {
    demographics_score:          analysis.demographics_score          ?? sc.demographics_score,
    foot_traffic_score:          analysis.foot_traffic_score          ?? sc.foot_traffic_score,
    foot_traffic_label:          sc.foot_traffic_label,
    income_score:                analysis.income_score                ?? sc.income_score,
    income_label:                sc.income_label,
    demographic_fit_score:       analysis.demographic_fit_score       ?? sc.demographic_fit_score,
    consumer_affordability_index:analysis.consumer_affordability_index ?? sc.consumer_affordability_index,
    median_weekly_income:        sc.adjusted_weekly_income,
    median_monthly_income:       sc.seifa_adjusted_monthly_income || sc.adjusted_monthly_income,
    median_annual_income:        sc.adjusted_annual_income,
    area_type:                   sc.area_type,
    is_premium_area:             sc.is_premium_area,
    city_tier:                   sc.city_tier,
    urban_density:               sc.urban_density,
    area_profile:                analysis.area_profile || null,
    suburb:sc.suburb,postcode:sc.postcode,state:sc.state,
    seifa_score:sc.seifa_score,seifa_label:sc.seifa_label,
    seifa_interpretation:        analysis.seifa_interpretation || null,
    foot_traffic_analysis:       analysis.foot_traffic_analysis || null,
    income_analysis:             analysis.income_analysis || null,
    demand_generator_breakdown:  analysis.demand_generator_breakdown || [],
    demand_generators_raw:       sc.demand_generators,
    overpass_counts: {
      total_pois:sc.overpass_demand_count,
      transit_stops:sc.overpass_transit_count,
      education_hubs:sc.overpass_edu_count
    },
    estimated_daily_customers_range: analysis.estimated_daily_customers_range || {
      low:Math.max(sc.est_daily_customers-10,1),
      base:sc.est_daily_customers,
      high:sc.est_daily_customers+20
    },
    target_segment_fit:          analysis.target_segment_fit    || sc.segment_alignment,
    seasonal_patterns:           analysis.seasonal_patterns     || null,
    demographic_risks:           analysis.demographic_risks     || [],
    demographic_opportunities:   analysis.demographic_opportunities || [],
    abs_data_quality:            analysis.abs_data_quality || (sc.abs_data_found?'Real ABS data':'State estimate'),
    data_confidence:             analysis.data_confidence     || 'Medium',
    data_confidence_note:        analysis.data_confidence_note|| null,
    overall_demographic_verdict: analysis.overall_demographic_verdict || 'Moderate Fit',
    population_per_sqkm:         sc.population_per_sqkm
  }
}}];

// ── Output validation ──
const required_keys = Object.keys(analysis).filter(k => !k.startsWith('_') && !k.startsWith('raw'));
if (required_keys.length < 3 || analysis.parse_error) {
  analysis._validation_failed = true;
  analysis._validation_reason = analysis.parse_error ? 'JSON parse error' : 'Insufficient output fields (' + required_keys.length + ')';
}
analysis._validated_at = new Date().toISOString();
analysis._agent_version = 'v2';

const j = $input.first().json;
const elements = j?.elements || [];

// Classify each element by its tags
let transit_count = 0, edu_count = 0, demand_count = 0;

const TRANSIT_HIGHWAY = ['bus_stop'];
const TRANSIT_RAILWAY = ['station','tram_stop','halt','stop'];
const EDU_AMENITY     = ['university','college','school','library'];
const DEMAND_AMENITY  = ['cafe','restaurant','bar','fast_food','bank','pharmacy'];
const DEMAND_SHOP     = ['supermarket','convenience'];

for (const el of elements) {
  const tags = el.tags || {};
  const hw = tags.highway || '';
  const rw = tags.railway || '';
  const am = tags.amenity || '';
  const sh = tags.shop    || '';
  const et = el.type      || '';

  if (TRANSIT_HIGHWAY.includes(hw) || TRANSIT_RAILWAY.includes(rw)) {
    transit_count++;
  } else if ((et === 'way' || et === 'relation') && EDU_AMENITY.includes(am)) {
    edu_count++;
  } else if (DEMAND_AMENITY.includes(am) || DEMAND_SHOP.includes(sh)) {
    demand_count++;
  }
}

return [{ json: {
  _type: 'combined',
  transit_count,
  edu_count,
  demand_count,
  total_elements: elements.length
}}];
